    40→			],
    41→		},
    42→		{
    43→			id: 'price',
    44→			check: (text) => !this.opensearchConversationalService.detectPriceLevels({ text }),
    45→			question: 'What is your budget range?',
    46→			options: [
    47→				{ label: 'Budget (under $10)', value: 'budget' },
    48→				{ label: 'Mid-range ($10–$20)', value: 'midrange' },
    49→				{ label: 'Premium ($20+)', value: 'premium' },
    50→			],
    51→		},
    52→		{
    53→			id: 'occasion',
    54→			check: (text) => !OCCASION_PATTERN.test(text),
    55→			question: 'What is the occasion or intended use?',
    56→			options: [
    57→				{ label: 'Casual / Everyday', value: 'casual' },
    58→				{ label: 'Sports / Outdoor', value: 'sports' },
    59→				{ label: 'Corporate / Business', value: 'corporate' },
    60→				{ label: 'Event / Fundraiser', value: 'event' },
    61→			],
    62→		},
    63→	];
    64→
    65→	@LogExecution({
    66→		paramFormatter: (
    67→			params: [
    68→				{
    69→					message: string;
    70→					conversationId?: string;
    71→					clarifications?: ClarificationAnswerDto[];
    72→				},
    73→			],
    74→		) => ({
    75→			message: params[0].message,
    76→			conversationId: params[0].conversationId,
    77→			hasClarifications: !!params[0].clarifications?.length,
    78→		}),
    79→		responseFormatter: (response: ConversationalSearchResponseDto) => ({
    80→			needsClarification: response.needsClarification,
    81→			conversationId: response.conversationId,
    82→			total: response.total,
    83→		}),
    84→	})
    85→	async chat({
    86→		message,
    87→		conversationId,
    88→		clarifications,
    89→	}: {
    90→		message: string;
    91→		conversationId?: string;
    92→		clarifications?: ClarificationAnswerDto[];
    93→	}): Promise<ConversationalSearchResponseDto> {
    94→		if (conversationId) {
    95→			return this.handleContinuation({ message, conversationId });
    96→		}
    97→
    98→		if (!clarifications?.length) {
    99→			return this.handleNewConversation({ message });
   100→		}
   101→
   102→		return this.handleWithClarifications({ message, clarifications });
   103→	}
   104→
   105→	private async handleContinuation({
   106→		message,
   107→		conversationId,
   108→	}: {
   109→		message: string;
   110→		conversationId: string;
   111→	}): Promise<ConversationalSearchResponseDto> {
   112→		const interactions = await this.opensearchService.getConversationInteractions({
   113→			conversationId,
   114→			maxResults: 5,
   115→		});
   116→
   117→		const contextParts = interactions
   118→			.slice(-3)
   119→			.map((i) => i.input)
   120→			.filter(Boolean);
   121→
   122→		const enrichedQuery = [...contextParts, message].join(' ');
   123→
   124→		const sanitized = this.opensearchConversationalService.sanitizeQuery({
   125→			text: enrichedQuery,
   126→		});
   127→		const normalized = this.opensearchConversationalService.normalizeQuery({
   128→			text: sanitized,
   129→		});
   130→
   131→		const products = await this.opensearchConversationalService.searchProducts({
   132→			queryText: normalized,
   133→		});
   134→
   135→		const summary = await this.generateSummary({
   136→			products: products.slice(0, 5),
   137→			originalMessage: message,
   138→			context: interactions.slice(-1)[0]?.response,
   139→		});
   140→
   141→		await this.opensearchService.addConversationInteraction({
   142→			conversationId,
   143→			input: normalized,
   144→			response: summary,
   145→			origin: 'conversational-search',
   146→		});
   147→
   148→		return {
   149→			needsClarification: false,
   150→			conversationId,
   151→			query: normalized,
   152→			summary,
   153→			total: products.length,
   154→			products,
   155→		};
   156→	}
   157→
   158→	private async handleNewConversation({
   159→		message,
   160→	}: {
   161→		message: string;
   162→	}): Promise<ConversationalSearchResponseDto> {
   163→		const sanitized = this.opensearchConversationalService.sanitizeQuery({
   164→			text: message,
   165→		});
   166→
   167→		const triggeredRules = this.CLARIFICATION_RULES.filter((rule) =>
   168→			rule.check(sanitized),
   169→		);
   170→
   171→		const hasStrongSignal = this.hasStrongProductSignal({ text: sanitized });
   172→
   173→		if (triggeredRules.length >= MIN_CLARIFICATIONS_NEEDED && !hasStrongSignal) {
   174→			const questions: ClarificationQuestionDto[] = triggeredRules.map((rule) => ({
   175→				id: rule.id,
   176→				question: rule.question,
   177→				options: rule.options,
   178→			}));
   179→
   180→			return { needsClarification: true, questions };
   181→		}
   182→
   183→		return this.handleWithClarifications({ message, clarifications: [] });
   184→	}
   185→
   186→	private async handleWithClarifications({
   187→		message,
   188→		clarifications,
   189→	}: {
   190→		message: string;
   191→		clarifications: ClarificationAnswerDto[];
   192→	}): Promise<ConversationalSearchResponseDto> {
   193→		const clarificationParts = clarifications.map((c) => {
   194→			const rule = this.CLARIFICATION_RULES.find((r) => r.id === c.questionId);
   195→			const option = rule?.options.find((o) => o.value === c.answer);
   196→			return option?.label ?? c.answer;
   197→		});
   198→
   199→		const enrichedQuery = [message, ...clarificationParts].filter(Boolean).join(' ');
   200→
   201→		const sanitized = this.opensearchConversationalService.sanitizeQuery({
   202→			text: enrichedQuery,
   203→		});
   204→		const normalized = this.opensearchConversationalService.normalizeQuery({
   205→			text: sanitized,
   206→		});
   207→
   208→		const products = await this.opensearchConversationalService.searchProducts({
   209→			queryText: normalized,
   210→		});
   211→
   212→		const summary = await this.generateSummary({
   213→			products: products.slice(0, 5),
   214→			originalMessage: message,
   215→			clarifications,
   216→		});
   217→
   218→		const conversationId = await this.opensearchService.createConversation({
   219→			name: message.substring(0, 50),
   220→		});
   221→
   222→		await this.opensearchService.addConversationInteraction({
   223→			conversationId,
   224→			input: normalized,
   225→			response: summary,
   226→			origin: 'conversational-search',
   227→		});
   228→
   229→		return {
   230→			needsClarification: false,
   231→			conversationId,
   232→			query: normalized,
   233→			summary,
   234→			total: products.length,
   235→			products,
   236→		};
   237→	}
   238→
   239→	private async generateSummary({
   240→		products,
   241→		originalMessage,
   242→		clarifications,
   243→		context,
   244→	}: {
   245→		products: { name: string; product_type?: string | null; brand?: string[] | null }[];
   246→		originalMessage: string;
   247→		clarifications?: ClarificationAnswerDto[];
   248→		context?: string;
   249→	}): Promise<string> {
   250→		try {
   251→			const llmModelId = this.opensearchConversationalService.getLlmModelId();
   252→
   253→			const productList = products
   254→				.map((p) => `- ${p.name} (${p.product_type ?? 'product'})`)
   255→				.join('\n');
   256→
   257→			const clarificationContext = clarifications?.length
   258→				? `Customer preferences: ${clarifications.map((c) => `${c.questionId}: ${c.answer}`).join(', ')}.`
   259→				: '';
   260→
   261→			const priorContext = context ? `Previous context: ${context}.` : '';
   262→
   263→			const messages = [
   264→				{
   265→					role: 'system',
   266→					content:
   267→						'You are a helpful product recommendation assistant. Provide brief, friendly summaries of product recommendations in 1-2 sentences.',
   268→				},
   269→				{
   270→					role: 'user',
   271→					content: `Customer request: "${originalMessage}". ${clarificationContext} ${priorContext}\n\nTop products found:\n${productList}\n\nProvide a brief summary of these recommendations.`,
   272→				},
   273→			];
   274→
   275→			return await this.opensearchService.predictModel({ modelId: llmModelId, messages });
   276→		} catch {
   277→			return `Found ${products.length} products matching your request.`;
   278→		}
   279→	}
   280→
   281→	private hasStrongProductSignal({ text }: { text: string }): boolean {
   282→		const strongSignals =
   283→			/\b(polo|hoodie|jacket|hat|cap|bag|mug|pen|notebook|shirt|pants|shorts|socks|shoes|sneakers|sweatshirt|fleece|vest|beanie|gloves|scarf|backpack|tote|water bottle|tumbler|keychain|lanyard|umbrella|polo shirt|t-shirt|tank top|zip-up|half-zip|long-sleeve|short-sleeve|crewneck|v-neck)\b/i;
   284→		return strongSignals.test(text) && text.split(' ').length >= 4;
   285→	}
