   287→	renderChatPageHtml(): string {
   288→		return `<!DOCTYPE html>
   289→<html>
   290→<head>
   291→  <meta charset="utf-8">
   292→  <title>Conversational Search</title>
   293→  <style>
   294→    * { box-sizing: border-box; }
   295→    body { font-family: system-ui, sans-serif; margin: 0; background: #f5f5f5; display: flex; flex-direction: column; height: 100vh; }
   296→    #header { padding: 16px 20px; background: #1e40af; color: #fff; font-size: 18px; font-weight: 600; }
   297→    #chat { flex: 1; overflow-y: auto; padding: 20px; display: flex; flex-direction: column; gap: 12px; }
   298→    .msg { max-width: 70%; padding: 10px 14px; border-radius: 12px; font-size: 14px; line-height: 1.5; }
   299→    .msg.user { align-self: flex-end; background: #2563eb; color: #fff; }
   300→    .msg.bot { align-self: flex-start; background: #fff; border: 1px solid #ddd; }
   301→    .products { display: flex; flex-wrap: wrap; gap: 10px; margin-top: 10px; }
   302→    .product-card { border: 1px solid #eee; border-radius: 8px; padding: 8px; width: 150px; text-align: center; background: #fafafa; font-size: 12px; }
   303→    .product-card img { width: 130px; height: 130px; object-fit: contain; }
   304→    .clarifications { display: flex; flex-direction: column; gap: 10px; }
   305→    .clarification-q { font-weight: 600; margin-bottom: 4px; }
   306→    .options { display: flex; flex-wrap: wrap; gap: 6px; }
   307→    .option-btn { padding: 6px 12px; border: 1px solid #2563eb; border-radius: 20px; background: #fff; color: #2563eb; cursor: pointer; font-size: 13px; }
   308→    .option-btn.selected { background: #2563eb; color: #fff; }
   309→    #form { display: flex; gap: 8px; padding: 12px 20px; background: #fff; border-top: 1px solid #ddd; }
   310→    #input { flex: 1; padding: 10px 14px; font-size: 14px; border: 1px solid #ccc; border-radius: 8px; outline: none; }
   311→    #send { padding: 10px 20px; background: #2563eb; color: #fff; border: none; border-radius: 8px; cursor: pointer; font-size: 14px; }
   312→    #send:disabled { background: #93c5fd; cursor: not-allowed; }
   313→  </style>
   314→</head>
   315→<body>
   316→  <div id="header">Conversational Product Search</div>
   317→  <div id="chat"></div>
   318→  <form id="form">
   319→    <input id="input" placeholder="Describe what you're looking for..." autocomplete="off" />
   320→    <button id="send" type="submit">Send</button>
   321→  </form>
   322→  <script>
   323→    var conversationId = null;
   324→    var pendingClarifications = null;
   325→    var pendingMessage = null;
   326→
   327→    function appendMsg(role, html) {
   328→      var div = document.createElement('div');
   329→      div.className = 'msg ' + role;
   330→      div.innerHTML = html;
   331→      document.getElementById('chat').appendChild(div);
   332→      document.getElementById('chat').scrollTop = 999999;
   333→    }
   334→
   335→    function renderProducts(products) {
   336→      if (!products || !products.length) return '';
   337→      return '<div class="products">' + products.slice(0, 10).map(function(p) {
   338→        return '<div class="product-card"><img src="' + (p.style_card_image_url || '') + '" onerror="this.style.display=\'none\'" /><div>' + p.name + '</div></div>';
   339→      }).join('') + '</div>';
   340→    }
   341→
   342→    function renderClarifications(questions) {
   343→      pendingClarifications = {};
   344→      return '<div class="clarifications">' + questions.map(function(q) {
   345→        return '<div><div class="clarification-q">' + q.question + '</div><div class="options" data-id="' + q.id + '">' +
   346→          q.options.map(function(o) {
   347→            return '<button class="option-btn" data-value="' + o.value + '" onclick="selectOption(this)">' + o.label + '</button>';
   348→          }).join('') + '</div></div>';
   349→      }).join('') + '<button onclick="submitClarifications()" style="margin-top:10px;padding:8px 16px;background:#2563eb;color:#fff;border:none;border-radius:6px;cursor:pointer;">Search</button></div>';
   350→    }
   351→
   352→    function selectOption(btn) {
   353→      var group = btn.parentElement;
   354→      group.querySelectorAll('.option-btn').forEach(function(b) { b.classList.remove('selected'); });
   355→      btn.classList.add('selected');
   356→      pendingClarifications[group.dataset.id] = btn.dataset.value;
   357→    }
   358→
   359→    function submitClarifications() {
   360→      var clarifications = Object.keys(pendingClarifications).map(function(k) {
   361→        return { questionId: k, answer: pendingClarifications[k] };
   362→      });
   363→      sendRequest({ message: pendingMessage, clarifications: clarifications });
   364→    }
   365→
   366→    function sendRequest(payload) {
   367→      document.getElementById('send').disabled = true;
   368→      fetch('/api/v1/conversational-search/chat', {
   369→        method: 'POST',
   370→        headers: { 'Content-Type': 'application/json' },
   371→        body: JSON.stringify(payload)
   372→      })
   373→      .then(function(r) { return r.json(); })
   374→      .then(function(data) {
   375→        if (data.needsClarification) {
   376→          pendingMessage = payload.message;
   377→          appendMsg('bot', renderClarifications(data.questions));
   378→        } else {
   379→          conversationId = data.conversationId;
   380→          var html = '';
   381→          if (data.summary) html += '<div>' + data.summary + '</div>';
   382→          if (data.total) html += '<div style="color:#666;font-size:12px;margin-top:4px;">Found ' + data.total + ' products</div>';
   383→          html += renderProducts(data.products);
   384→          appendMsg('bot', html);
   385→        }
   386→      })
   387→      .catch(function() { appendMsg('bot', 'Something went wrong. Please try again.'); })
   388→      .finally(function() { document.getElementById('send').disabled = false; });
   389→    }
   390→
   391→    document.getElementById('form').addEventListener('submit', function(e) {
