   398→      pendingClarifications = null;
   399→      var payload = { message: msg };
   400→      if (conversationId) payload.conversationId = conversationId;
   401→      sendRequest(payload);
   402→    });
   403→  </script>
   404→</body>
   405→</html>`;
   406→	}
   407→}
